import tarfile
import os

def extract_tar(src_path, dest_dir):
    # Create a new tar file object
    tar = tarfile.open(src_path)
    
    # Extract the tar file to the destination directory
    tar.extractall(dest_dir)
    
    # Close the tar file object
    tar.close()